(315,"多选","企业财务管理的内容包括（）。",["A","B","C","D"],"企业财务管理内容包括筹资管理、投资管理、营运资金管理、成本管理、收入与分配管理。选A、B、C、D。",[("A","筹资管理"),("B","投资管理"),("C","营运资金管理"),("D","成本管理")]),
