(322,"单选","货币时间价值是指（）。",["B"],"货币时间价值是货币经历一定时间的投资和再投资所增加的价值。选B。",[("A","货币的购买力"),("B","货币经历一定时间的投资和再投资所增加的价值"),("C","通货膨胀带来的货币贬值"),("D","存款获得的利息收入")]),
